export function getWeaponPrefab(weaponTypeId: WeaponTypeId, variantIndex: number): WeaponVariant | null {
  const variants = WEAPON_PREFAB_VARIANTS[weaponTypeId];
  if (!variants || variantIndex < 0 || variantIndex >= variants.length) return null;
  return variants[variantIndex];
}

export function getWeaponPrefabByName(weaponTypeId: WeaponTypeId, variantName: string): WeaponVariant | null {
  const variants = WEAPON_PREFAB_VARIANTS[weaponTypeId];
  if (!variants) return null;
  return variants.find(v => v.name === variantName) || null;
}

export function getAllPrefabsForType(weaponTypeId: WeaponTypeId): WeaponVariant[] {
  return WEAPON_PREFAB_VARIANTS[weaponTypeId] || [];
}

export function getSkillAnimForWeapon(weaponTypeId: WeaponTypeId, variantIndex: number, skillName: string): SkillAnimMapping | null {
  const variant = getWeaponPrefab(weaponTypeId, variantIndex);
  if (!variant) return null;
  return variant.skillAnims.find(s => s.skillName === skillName) || null;
}

